public int[] prevPermOpt1(int[] arr) {
    int n = arr.length;
    for (int i = n - 2; i >= 0; i--) {
        if (arr[i] > arr[i + 1]) {
            int j = i + 1;
            while (j < n && arr[j] < arr[i]) j++;
            int temp = arr[i];
            arr[i] = arr[j - 1];
            arr[j - 1] = temp;
            break;
        }
    }
    return arr;
}
```


